INSERT INTO tb_order (
    tenant_id, order_no, buyer_company_id, seller_company_id, 
    order_date, order_status, total_supply_amount, total_vat_amount, 
    total_order_amount, payment_status, shipment_status, description, created_by
) VALUES (
    #{tenantId}, #{orderNo}, #{buyerCompanyId}, #{sellerCompanyId}, 
    #{orderDate}, #{orderStatus}, #{totalSupplyAmount}, #{totalVatAmount}, 
    #{totalOrderAmount}, #{paymentStatus}, #{shipmentStatus}, #{description}, #{createdBy}
)

