SET FOREIGN_KEY_CHECKS = 0;
DROP TABLE IF EXISTS tb_order_line; DROP TABLE IF EXISTS tb_order;
CREATE TABLE tb_order ( order_id BIGINT NOT NULL AUTO_INCREMENT, tenant_id BIGINT NOT NULL, seller_company_id BIGINT NOT NULL, buyer_company_id BIGINT NOT NULL, channel_id BIGINT NULL, order_no VARCHAR(50) NOT NULL, order_status ENUM('RECEIVED','CONFIRMED','COMPLETED','CANCELLED') NOT NULL DEFAULT 'RECEIVED', payment_status ENUM('UNPAID','PAID','PARTIAL_PAID') NOT NULL DEFAULT 'UNPAID', shipment_status ENUM('NOT_STARTED','PARTIAL','SHIPPED','DELIVERED') NOT NULL DEFAULT 'NOT_STARTED', total_supply_amount DECIMAL(18,2) NOT NULL DEFAULT 0, total_vat_amount DECIMAL(18,2) NOT NULL DEFAULT 0, total_order_amount DECIMAL(18,2) NOT NULL DEFAULT 0, description TEXT NULL, created_by BIGINT NULL, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, PRIMARY KEY (order_id), UNIQUE KEY uq_tb_order_01 (order_no), KEY idx_tb_order_01 (tenant_id, buyer_company_id, order_status), KEY idx_tb_order_02 (tenant_id, seller_company_id, payment_status) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE tb_order_line ( order_line_id BIGINT NOT NULL AUTO_INCREMENT, order_id BIGINT NOT NULL, line_no INT NOT NULL, product_id BIGINT NOT NULL, relation_group_id VARCHAR(50) NULL, product_name_snapshot VARCHAR(200) NOT NULL, qty DECIMAL(12,3) NOT NULL DEFAULT 0, unit_price DECIMAL(18,2) NOT NULL DEFAULT 0, supply_amount DECIMAL(18,2) NOT NULL DEFAULT 0, vat_amount DECIMAL(18,2) NOT NULL DEFAULT 0, total_amount DECIMAL(18,2) NOT NULL DEFAULT 0, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, PRIMARY KEY (order_line_id), KEY idx_tb_order_line_01 (order_id) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
SET FOREIGN_KEY_CHECKS = 1;

