SELECT o.*, bc.company_name as buyer_company_name, sc.company_name as seller_company_name FROM tb_order o LEFT JOIN tb_company bc ON o.buyer_company_id = bc.company_id LEFT JOIN tb_company sc ON o.seller_company_id = sc.company_id WHERE 1=1
AND o.order_no LIKE CONCAT('%', #{searchKeyword}, '%')
AND o.order_status = #{orderStatus}
ORDER BY o.order_id DESC LIMIT #{recordCountPerPage} OFFSET #{firstIndex}

SELECT COUNT(*) FROM tb_order o WHERE 1=1
AND o.order_no LIKE CONCAT('%', #{searchKeyword}, '%')
AND o.order_status = #{orderStatus}
